import asyncio
from langchain_core.runnables import RunnableLambda


async def async_llm_call(prompt):
    await asyncio.sleep(0.01)
    return {'text': f'response to {prompt}'}


def build_chain():
    # BUG: wraps async fn in RunnableLambda but caller uses .invoke not .ainvoke
    return RunnableLambda(async_llm_call)


def run_agent(query):
    chain = build_chain()
    return chain.invoke({'q': query})


async def main():
    query = 'hello'
    result = run_agent(query)
    print(result)


if __name__ == '__main__':
    asyncio.run(main())
